fn round_trip(r: f32, g: f32, b: f32) {
        let (l, a, lab_b) = srgb_to_lab(r, g, b);
        let (r2, g2, b2) = lab_to_srgb(l, a, lab_b);
        assert!(
            (r2 - r).abs() < 1e-3 && (g2 - g).abs() < 1e-3 && (b2 - b).abs() < 1e-3,
            "Round-trip ({r},{g},{b}) -> Lab({l:.2},{a:.2},{lab_b:.2}) -> ({r2:.5},{g2:.5},{b2:.5})"
        );
    }
